    tr[x]=1e16;

    if(l==r) return ;

    bu(x*2,l,(l+r)/2);

    bu(x*2+1,(l+r)/2+1,r);

}

void up(int x){

    if(p[x]){

        if(p[x*2]==0) p[x*2]=p[x];

        else p[x*2]=min(p[x*2],p[x]);

        if(p[x*2+1]==0) p[x*2+1]=p[x];

        else p[x*2+1]=min(p[x*2+1],p[x]);

        tr[x*2]=min(tr[x*2],p[x]);

        tr[x*2+1]=min(tr[x*2+1],p[x]);

        p[x]=0;

    }

}

ll fi(int x,int l,int r,int y){

    if(y==1) return 0;

    if(l==r) return tr[x];

    up(x);

    if((l+r)/2>=y) return fi(x*2,l,(l+r)/2,y);

    return fi(x*2+1,(l+r)/2+1,r,y);

}

